using namespace std;

typedef long long ll;

// Global modulus
const int MOD = 1e9 + 7;

/**
 * @brief Calculates the digit sum of a number.
 * 
 * @param n The number.
 * @return The sum of its digits.
 */
int calculate_digit_sum(int n) {
    int sum = 0;
    string s = to_string(n);
    for (char c : s) {
        sum += c - '0';
    }
    return sum;
}

/**
 * @brief Generates all numbers <= 5000 with a specific digit sum.
 * 
 * @param target_sum The required digit sum.
 * @return A vector of integers satisfying the conditions.
 */
vector<int> generate_numbers(int target_sum) {
    vector<int> numbers;
    for (int i = 0; i <= 5000; ++i) {
        if (calculate_digit_sum(i) == target_sum) {
            numbers.push_back(i);
        }
    }
    return numbers;
}

/**
 * @brief Solves the main problem using dynamic programming.
 * 
 * @param digitSum The array of required digit sums.
 * @return The number of valid arrays modulo 10^9 + 7.
 */
ll solve(vector<int64>& digitSum) {
    int n = digitSum.size();

    // Step 1: Precompute the set of valid numbers for each required digit sum.
    // Since digitSum[i] <= 50, we can use a map or an array of vectors.
    // We only need to compute this once for all distinct required sums.
    map<int, vector<int>> precomputed_numbers;

    // Since digitSum elements are int64, we cast them to int as per constraints (0 <= digitSum[i] <= 50).
    for (int64 ds_val : digitSum) {
        int target_sum = (int)ds_val;
        if (precomputed_numbers.find(target_sum) == precomputed_numbers.end()) {
            precomputed_numbers[target_sum] = generate_numbers(target_sum);
            // Sort them to easily check the non-decreasing property later.
            sort(precomputed_numbers[target_sum].begin(), precomputed_numbers[target_sum].end());
        }
    }

    // Step 2: Dynamic Programming
    // dp[i][j] will store the number of valid arrays of length i+1 
    // where the last element (arr[i]) is the j-th number in the precomputed list 
    // for digitSum[i]. This seems too complex due to the varying sets.

    // A simpler DP approach:
    // dp[i][prev_val] = number of valid prefixes of length i+1 ending with value prev_val.
    // Since prev_val can be up to 5000, this is feasible.

    // Let's map the possible values to indices for DP state if the set of values is small.
    // The maximum value is 5000.

    // dp[i][v]: Number of valid arrays of length i+1 ending with value v.
    // i ranges from 0 to n-1. v ranges from 0 to 5000.

    // Since n <= 1000 and 5001 states, O(N * V^2) or O(N * V * |Set|) might be too slow.
    // Total complexity: N * (Number of valid predecessors * 1).

    // Let's use DP based on the index in the precomputed list.
    // dp[i][j]: Number of valid prefixes of length i+1 where arr[i] is the j-th number in precomputed_numbers[digitSum[i]].

    vector<vector<ll>> dp(n);

    for (int i = 0; i < n; ++i) {
        int target_sum = (int)digitSum[i];
        const auto& current_numbers = precomputed_numbers[target_sum];
        int count_current = current_numbers.size();

        dp[i].assign(count_current, 0);

        if (i == 0) {
            // Base case: Length 1 array. Any valid number works.
            for (int j = 0; j < count_current; ++j) {
                dp[i][j] = 1;
            }
        } else {
