            int prev_target_sum = (int)digitSum[i-1];
            const auto& prev_numbers = precomputed_numbers[prev_target_sum];
            int count_prev = prev_numbers.size();

            for (int j = 0; j < count_current; ++j) { // current number index j
                int current_val = current_numbers[j];
                ll sum = 0;

                for (int k = 0; k < count_prev; ++k) { // previous number index k
                    int prev_val = prev_numbers[k];

                    // Check non-decreasing condition: arr[i] >= arr[i-1]
                    if (current_val >= prev_val) {
                        sum = (sum + dp[i-1][k]) % MOD;
                    }
                }
                dp[i][j] = sum;
            }
        }
    }

    // Step 3: Final result
    ll total_count = 0;
    for (int j = 0; j < dp[n-1].size(); ++j) {
        total_count = (total_count + dp[n-1][j]) % MOD;
    }

    return total_count;
}
