// Function to calculate the sum of digits of a number
int digit_sum(int n) {
    int sum = 0;
    while (n > 0) {
        sum += n % 10;
        n /= 10;
    }
    return sum;
}

// Precompute all numbers in [0, 5000] and their digit sums
map<int, vector<int>> precompute_numbers() {
    map<int, vector<int>> sums_to_numbers;
    for (int i = 0; i <= 5000; ++i) {
        int ds = digit_sum(i);
        sums_to_numbers[ds].push_back(i);
    }
    // Sort the numbers for easier non-decreasing checks later
    for (auto& pair : sums_to_numbers) {
        sort(pair.second.begin(), pair.second.end());
    }
    return sums_to_numbers;
}

// Helper function for modular addition
ll add(ll a, ll b) {
    return (a + b) % MOD;
}

// Helper function for modular multiplication
ll mul(ll a, ll b) {
    return (a * b) % MOD;
}

// Main solver function
ll solve(vector<int64>& digitSum) {
    // 1. Precompute numbers for all possible digit sums (0 to 50) in [0, 5000]
    map<int, vector<int>> sums_to_numbers = precompute_numbers();

    int n = digitSum.size();

    // DP state: dp[i][last_val_index] is the number of valid sequences 
    // of length i+1 ending with a number corresponding to index last_val_index 
    // in the sorted list of numbers that satisfy digitSum[i].

    // Since the number of candidates for each digitSum[i] can be large, 
    // we need a way to map values to DP states.

    // Let's change the DP state structure.
    // We iterate through the array digitSum one by one.
    // dp[i][j] = Number of valid arrays of length i+1, where the (i+1)-th element is the j-th smallest number 
    // whose digit sum is digitSum[i].

    // Let candidates[i] be the sorted list of numbers <= 5000 whose digit sum is digitSum[i].
    vector<vector<int>> candidates(n);
    for (int i = 0; i < n; ++i) {
        int ds = (int)digitSum[i];
        if (sums_to_numbers.count(ds)) {
            candidates[i] = sums_to_numbers.at(ds);
        } else {
            // If no number exists in [0, 5000] with the required digit sum, the answer is 0.
            return 0;
        }
    }

    // DP initialization: dp[i] will store the count for sequences ending at step i.
    // dp[i] is a vector where dp[i][j] is the count of valid arrays of length i+1 
    // ending with candidates[i][j].

    // We only need the previous step's counts.
    // prev_dp: map from number value to count (for step i-1)
    // current_dp: map from number value to count (for step i)

    // Step 0 (i=0)
    vector<ll> prev_dp(candidates[0].size(), 1); // Each candidate for the first element forms 1 valid array.

    // Iterate from the second element (i=1) up to n-1
    for (int i = 1; i < n; ++i) {
        int m_prev = candidates[i-1].size();
        int m_curr = candidates[i].size();

        vector<ll> current_dp(m_curr, 0);

        // Calculate current_dp[j] for candidates[i][j]
        for (int j = 0; j < m_curr; ++j) { // For the current number C_curr = candidates[i][j]
            ll count = 0;

            // Sum up counts from previous numbers C_prev = candidates[i-1][k] such that C_prev <= C_curr
            for (int k = 0; k < m_prev; ++k) {
                int C_prev = candidates[i-1][k];
                int C_curr = candidates[i][j];

                if (C_prev <= C_curr) {
                    // Add the count ending at C_prev in the previous step
                    count = add(count, prev_dp[k]);
                } else {
                    // Since both candidate lists are sorted, we can break early
                    break;
                }
            }
            current_dp[j] = count;
        }

        // Move current_dp to prev_dp for the next iteration
        prev_dp = current_dp;
    }

    // Final result: Sum up all counts in the final DP state (prev_dp holds the counts for i=n-1)
    ll total_count = 0;
    for (ll count : prev_dp) {
        total_count = add(total_count, count);
    }

    return total_count;
}
